import logo from "./logo.svg";
import hT_DESIGN from "./img_heroTitle01.png";
import hT_CODE from "./img_heroTitle02.png";
import hT_PUBLISHING from "./img_heroTitle03.png";
import profile_Img from "./img_profile.png";
import profile_parentheses from "./img_parentheses.svg";

export { logo };

export const heroTitle = {
  hT_DESIGN,
  hT_CODE,
  hT_PUBLISHING
};

export const profileImg = {
  profile_Img,
  profile_parentheses
};
